class Solution {
public:
    string longestPalindrome(string s) {
        int max_length = 0;
        int start = 0;
        int n = s.size();
        for (int i = 0; i < n; i++) {
            // Check for odd length palindromes
            int l = i, r = i;
            while (l >= 0 && r < n && s[l] == s[r]) {
                if (r - l + 1 > max_length) {
                    max_length = r - l + 1;
                    start = l;
                }
                l--;
                r++;
            }
            // Check for even length palindromes
            l = i;
            r = i + 1;
            while (l >= 0 && r < n && s[l] == s[r]) {
                if (r - l + 1 > max_length) {
                    max_length = r - l + 1;
                    start = l;
                }
                l--;
                r++;
            }
        }
        return s.substr(start, max_length);
    }
};

